+import { $internal } from '../common';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord } from './types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: MergeAspectSchemas<TTraits>;
+    readonly [$aspect]: true;
+} & ((value?: Partial<MergeAspectRecords<TTraits>>) => [Aspect<TTraits>, Partial<MergeAspectRecords<TTraits>>]);
+
+type Merge<T extends readonly object[]> = T extends readonly [infer First extends object, ...infer Rest extends object[]]
+    ? First & Merge<Rest>
+    : {};
+
+export type MergeAspectSchemas<T extends readonly Trait[]> = Merge<{
+    [K in keyof T]: T[K] extends Trait<infer S> ? S : never;
+}> extends infer Result extends object ? Result : never;
+
+export type MergeAspectRecords<T extends readonly Trait[]> = Merge<{
+    [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never;
+}> extends infer Result extends object ? Result : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+function flatten(inputs: readonly (Trait | Aspect)[]): Trait[] {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+    return traits;
+}
+
+export function createAspect<T extends readonly [Trait | Aspect, Trait | Aspect, ...(Trait | Aspect)[]]>(
+    ...inputs: T
+): Aspect<readonly Trait[]> {
+    const traits = flatten(inputs);
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const trait of traits) {
+        if (trait[$internal].relation) throw new Error('Aspects cannot contain relation traits');
+        for (const field of Object.keys(trait.schema as Schema)) {
+            if (fields.has(field)) throw new Error(`Aspect traits cannot share the field "${field}"`);
+            fields.add(field);
+            schema[field] = (trait.schema as Record<string, unknown>)[field];
+        }
+    }
+
+    const Aspect = Object.assign(
+        (value: Partial<MergeAspectRecords<typeof traits>> = {}) => [Aspect, value] as const,
+        { id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema), [$aspect]: true as const }
+    ) as Aspect<readonly Trait[]>;
+    return Aspect;
+}
+
+export function getAspectTraits(input: Trait | Aspect): readonly Trait[] {
+    return isAspect(input) ? input.traits : [input];
+}
