+/** Query result path for aspects, whose constituent data is exposed as one merged object. */
+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+): QueryResult<any> {
+    const readable = params.filter((param) => !isModifier(param) || param.type !== 'not');
+    const read = (entity: Entity) => readable.flatMap((param) => {
+        if (isAspect(param)) return [getTrait(world, entity, param as any)];
+        if (isModifier(param)) return param.traits.filter((trait) => trait[$internal].type !== 'tag').map((trait) => getTrait(world, entity, trait));
+        if (isRelationPair(param)) return [getTrait(world, entity, param)];
+        return (param as Trait)[$internal].type === 'tag' ? [] : [getTrait(world, entity, param as Trait)];
+    });
+    const results = Object.assign(entities, {
+        readEach(callback: any) {
+            for (let i = 0; i < entities.length; i++) callback(read(entities[i]), entities[i], i);
+            return results;
+        },
+        updateEach(callback: any, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = read(entity);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                let index = 0;
+                for (const param of readable) {
+                    if (isAspect(param)) {
+                        const aspect = param as Aspect;
+                        for (const trait of aspect.traits) {
+                            if (trait[$internal].type === 'tag') continue;
+                            const before = getTrait(world, entity, trait);
+                            const value = Object.fromEntries(Object.keys(trait.schema).map((key) => [key, state[index][key]]));
+                            if (options.changeDetection === 'never') setTrait(world, entity, trait, value, false);
+                            else if (!shallowEqual(before, value)) setTrait(world, entity, trait, value, true);
+                        }
+                        index++;
+                    } else if (isModifier(param)) {
+                        index += param.traits.filter((trait) => trait[$internal].type !== 'tag').length;
+                    } else if (!isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') index++;
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) { callback([], entities); return results; },
+        select(...selected: QueryParameter[]) { return createAspectQueryResult(world, entities, query, selected); },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<any>;
+}
